}

starLiteDocs({
  title: "My Docs",
});

starLiteDocs({
  sidebar: [
    { label: "Home", link: "/" },
    {
      label: "Guides",
      items: [
        { label: "Getting Started", link: "/getting-started" },
      ],
    },
  ],
});

// Custom Expressive Code options
starLiteDocs({
  expressiveCode: {
    themes: ["github-dark", "github-light"],
  },
});

// Disable entirely (use your own)
starLiteDocs({
  expressiveCode: false,
});

